def _unpack_args(
    args: cabc.Sequence[str], nargs_spec: cabc.Sequence[int]
) -> tuple[cabc.Sequence[str | cabc.Sequence[str | T_UNSET] | T_UNSET], list[str]]:
    """Given an iterable of arguments and an iterable of nargs specifications,
    it returns a tuple with all the unpacked arguments at the first index
    and all remaining arguments as the second.

    The nargs specification is the number of arguments that should be consumed
    or `-1` to indicate that this position should eat up all the remainders.

    Missing items are filled with ``UNSET``.
    """
    args = deque(args)
    nargs_spec = deque(nargs_spec)
    rv: list[str | tuple[str | T_UNSET, ...] | T_UNSET] = []
    spos: int | None = None

    def _fetch(c: deque[str]) -> str | T_UNSET:
        try:
            if spos is None:
                return c.popleft()
            else:
                return c.pop()
        except IndexError:
            return UNSET

    while nargs_spec:
        if spos is None:
            nargs = nargs_spec.popleft()
        else:
            nargs = nargs_spec.pop()

        if nargs == 1:
            rv.append(_fetch(args))
        elif nargs > 1:
            x: list[str | T_UNSET] = [_fetch(args) for _ in range(nargs)]

            # If we're reversed, we're pulling in the arguments in reverse,
            # so we need to turn them around.
            if spos is not None:
                x.reverse()

            rv.append(tuple(x))
        elif nargs < 0:
            if spos is not None:
                raise TypeError("Cannot have two nargs < 0")

            spos = len(rv)
            rv.append(UNSET)

    # spos is the position of the wildcard (star).  If it's not `None`,
    # we fill it with the remainder.
    if spos is not None:
        rv[spos] = tuple(args)
        args = []
        rv[spos + 1 :] = reversed(rv[spos + 1 :])

    return tuple(rv), list(args)

def _split_opt(opt: str) -> tuple[str, str]:
    first = opt[:1]
    if first.isalnum():
        return "", opt
    if opt[1:2] == first:
        return opt[:2], opt[2:]
    return first, opt[1:]

def _normalize_opt(opt: str, ctx: Context | None) -> str:
    if ctx is None or ctx.token_normalize_func is None:
        return opt
    prefix, opt = _split_opt(opt)
    return f"{prefix}{ctx.token_normalize_func(opt)}"

def _fetch(c: deque[str]) -> str | T_UNSET:
    try:
        if spos is None:
            return c.popleft()
        else:
            return c.pop()
    except IndexError:
        return UNSET

def __init__(
    self,
    obj: CoreOption,
    opts: cabc.Sequence[str],
    dest: str | None,
    action: str | None = None,
    nargs: int = 1,
    const: t.Any | None = None,
):
    self._short_opts = []
    self._long_opts = []
    self.prefixes: set[str] = set()

    for opt in opts:
        prefix, value = _split_opt(opt)
        if not prefix:
            raise ValueError(
                _("Invalid start character for option ({option})").format(
                    option=opt
                )
            )
        self.prefixes.add(prefix[0])
        if len(prefix) == 1 and len(value) == 1:
            self._short_opts.append(opt)
        else:
            self._long_opts.append(opt)
            self.prefixes.add(prefix)

    if action is None:
        action = "store"

    self.dest = dest
    self.action = action
    self.nargs = nargs
    self.const = const
    self.obj = obj

def process(self, value: t.Any, state: _ParsingState) -> None:
    if self.action == "store":
        state.opts[self.dest] = value  # type: ignore
    elif self.action == "store_const":
        state.opts[self.dest] = self.const  # type: ignore
    elif self.action == "append":
        state.opts.setdefault(self.dest, []).append(value)  # type: ignore
    elif self.action == "append_const":
        state.opts.setdefault(self.dest, []).append(self.const)  # type: ignore
    elif self.action == "count":
        state.opts[self.dest] = state.opts.get(self.dest, 0) + 1  # type: ignore
    else:
        raise ValueError(f"unknown action '{self.action}'")
    state.order.append(self.obj)

def process(
    self,
    value: str | cabc.Sequence[str | T_UNSET] | T_UNSET,
    state: _ParsingState,
) -> None:
    if self.nargs > 1:
        assert isinstance(value, cabc.Sequence)
        holes = sum(x is UNSET for x in value)
        if holes == len(value):
            value = UNSET
        elif holes != 0:
            raise BadArgumentUsage(
                _("Argument {name!r} takes {nargs} values.").format(
                    name=self.dest, nargs=self.nargs
                )
            )

    # We failed to collect any argument value so we consider the argument as unset.
    if value == ():
        value = UNSET

    state.opts[self.dest] = value  # type: ignore
    state.order.append(self.obj)

def __init__(self, rargs: list[str]) -> None:
    self.opts: dict[str, t.Any] = {}
    self.largs: list[str] = []
    self.rargs = rargs
    self.order: list[CoreParameter] = []

def _process_args_for_args(self, state: _ParsingState) -> None:
    pargs, args = _unpack_args(
        state.largs + state.rargs, [x.nargs for x in self._args]
    )

    for idx, arg in enumerate(self._args):
        arg.process(pargs[idx], state)

    state.largs = args
    state.rargs = []

def _process_args_for_options(self, state: _ParsingState) -> None:
    while state.rargs:
        arg = state.rargs.pop(0)
        arglen = len(arg)
        # Double dashes always handled explicitly regardless of what
        # prefixes are valid.
        if arg == "--":
            return
        elif arg[:1] in self._opt_prefixes and arglen > 1:
            self._process_opts(arg, state)
        elif self.allow_interspersed_args:
            state.largs.append(arg)
        else:
            state.rargs.insert(0, arg)
            return

def _match_long_opt(
    self, opt: str, explicit_value: str | None, state: _ParsingState
) -> None:
    if opt not in self._long_opt:
        raise NoSuchOption(opt, possibilities=self._long_opt, ctx=self.ctx)

    option = self._long_opt[opt]
    if option.takes_value:
        # At this point it's safe to modify rargs by injecting the
        # explicit value, because no exception is raised in this
        # branch.  This means that the inserted value will be fully
        # consumed.
        if explicit_value is not None:
            state.rargs.insert(0, explicit_value)

        value = self._get_value_from_state(opt, option, state)

    elif explicit_value is not None:
        raise BadOptionUsage(
            opt, _("Option {name!r} does not take a value.").format(name=opt)
        )

    else:
        value = UNSET

    option.process(value, state)

def _get_value_from_state(
    self, option_name: str, option: _Option, state: _ParsingState
) -> str | cabc.Sequence[str] | T_UNSET | T_FLAG_NEEDS_VALUE:
    nargs = option.nargs

    value: str | cabc.Sequence[str] | T_UNSET | T_FLAG_NEEDS_VALUE

    if len(state.rargs) < nargs:
        if option.obj._flag_needs_value:
            # Option allows omitting the value.
            value = FLAG_NEEDS_VALUE
        else:
            raise BadOptionUsage(
                option_name,
                ngettext(
                    "Option {name!r} requires an argument.",
                    "Option {name!r} requires {nargs} arguments.",
                    nargs,
                ).format(name=option_name, nargs=nargs),
            )
    elif nargs == 1:
        next_rarg = state.rargs[0]

        if (
            option.obj._flag_needs_value
            and isinstance(next_rarg, str)
            and next_rarg[:1] in self._opt_prefixes
            and len(next_rarg) > 1
        ):
            # The next arg looks like the start of an option, don't
            # use it as the value if omitting the value is allowed.
            value = FLAG_NEEDS_VALUE
        else:
            value = state.rargs.pop(0)
    else:
        value = tuple(state.rargs[:nargs])
        del state.rargs[:nargs]

    return value

def _start_of_option(ctx: Context, value: str) -> bool:
    """Check if the value looks like the start of an option."""
    if not value:
        return False

    c = value[0]
    return c in ctx._opt_prefixes

def _is_incomplete_option(ctx: Context, args: list[str], param: Parameter) -> bool:
    """Determine if the given parameter is an option that needs a value.

    :param args: List of complete args before the incomplete value.
    :param param: Option object being checked.
    """
    if not isinstance(param, Option):
        return False

    if param.is_flag or param.count:
        return False

    last_option = None

    for index, arg in enumerate(reversed(args)):
        if index + 1 > param.nargs:
            break

        if _start_of_option(ctx, arg):
            last_option = arg
            break

    return last_option is not None and last_option in param.opts

def source_vars(self) -> _SourceVarsDict:
    """Vars for formatting :attr:`source_template`.

    By default this provides ``complete_func``, ``complete_var``,
    and ``prog_name``.
    """
    return {
        "complete_func": self.func_name,
        "complete_var": self.complete_var,
        "prog_name": self.prog_name,
    }

def _check_version() -> None:
    import shutil
    import subprocess

    bash_exe = shutil.which("bash")

    if bash_exe is None:
        match = None
    else:
        output = subprocess.run(
            [bash_exe, "--norc", "-c", 'echo "${BASH_VERSION}"'],
            stdout=subprocess.PIPE,
        )
        match = re.search(r"^(\d+)\.(\d+)\.\d+", output.stdout.decode())

    if match is not None:
        major, minor = match.groups()

        if major < "4" or major == "4" and minor < "4":
            echo(
                _(
                    "Shell completion is not supported for Bash"
                    " versions older than 4.4."
                ),
                err=True,
            )
    else:
        echo(
            _("Couldn't detect Bash version, shell completion is not supported."),
            err=True,
        )

def source(self) -> str:
    self._check_version()
    return super().source()

def get_completion_args(self) -> tuple[list[str], str]:
    cwords = split_arg_string(os.environ["COMP_WORDS"])
    cword = int(os.environ["COMP_CWORD"])
    args = cwords[1:cword]

    try:
        incomplete = cwords[cword]
    except IndexError:
        incomplete = ""

    return args, incomplete

def get_completion_args(self) -> tuple[list[str], str]:
    cwords = split_arg_string(os.environ["COMP_WORDS"])
    cword = int(os.environ["COMP_CWORD"])
    args = cwords[1:cword]

    try:
        incomplete = cwords[cword]
    except IndexError:
        incomplete = ""

    return args, incomplete

def hidden_prompt_func(prompt: str) -> str:
    import getpass

    return getpass.getpass(prompt)

def _build_prompt(
    text: str,
    suffix: str,
    show_default: bool | str = False,
    default: t.Any | None = None,
    show_choices: bool = True,
    type: ParamType[t.Any] | None = None,
) -> str:
    prompt = text
    if type is not None and show_choices and isinstance(type, Choice):
        prompt += f" ({', '.join(map(str, type.choices))})"
    if isinstance(show_default, str):
        default = f"({show_default})"
    if default is not None and show_default:
        prompt = f"{prompt} [{_format_default(default)}]"
    return f"{prompt}{suffix}"

def _format_default(default: t.Any) -> t.Any:
    if isinstance(default, (io.IOBase, LazyFile)) and hasattr(default, "name"):
        return default.name

    return default

def clear() -> None:
    """Clears the terminal screen.  This will have the effect of clearing
    the whole visible space of the terminal and moving the cursor to the
    top left.  This does not do anything if not connected to a terminal.

    .. versionadded:: 2.0
    """
    if not isatty(sys.stdout):
        return

    # ANSI escape \033[2J clears the screen, \033[1;1H moves the cursor
    echo("\033[2J\033[1;1H", nl=False)

def _interpret_color(color: int | tuple[int, int, int] | str, offset: int = 0) -> str:
    if isinstance(color, int):
        return f"{38 + offset};5;{color:d}"

    if isinstance(color, (tuple, list)):
        r, g, b = color
        return f"{38 + offset};2;{r:d};{g:d};{b:d}"

    return str(_ansi_colors[color] + offset)

def raw_terminal() -> AbstractContextManager[int]:
    from ._termui_impl import raw_terminal as f

    return f()

def pause(info: str | None = None, err: bool = False) -> None:
    """This command stops execution and waits for the user to press any
    key to continue.  This is similar to the Windows batch "pause"
    command.  If the program is not run through a terminal, this command
    will instead do nothing.

    .. versionadded:: 2.0

    .. versionadded:: 4.0
       Added the `err` parameter.

    :param info: The message to print before pausing. Defaults to
        ``"Press any key to continue..."``.
    :param err: if set to message goes to ``stderr`` instead of
                ``stdout``, the same as with echo.
    """
    if not isatty(sys.stdin) or not isatty(sys.stdout):
        return

    if info is None:
        info = _("Press any key to continue...")

    try:
        if info:
            echo(info, nl=False, err=err)
        try:
            getchar()
        except (KeyboardInterrupt, EOFError):
            pass
    finally:
        if info:
            echo(err=err)

def prompt_func(text: str) -> str:
    f = hidden_prompt_func if hide_input else visible_prompt_func
    try:
        return _readline_prompt(f, text, err)
    except (KeyboardInterrupt, EOFError):
        # getpass doesn't print a newline if the user aborts input with ^C.
        # Allegedly this behavior is inherited from getpass(3).
        # A doc bug has been filed at https://bugs.python.org/issue24711
        if hide_input:
            echo(None, err=err)
        raise Abort() from None

def _pause_echo(stream: EchoingStdin | None) -> cabc.Generator[None]:
    if stream is None:
        yield
    else:
        stream._paused = True
        yield
        stream._paused = False

def make_input_stream(
    input: str | bytes | t.IO[t.Any] | None, charset: str
) -> t.BinaryIO:
    # Is already an input stream.
    if hasattr(input, "read"):
        rv = _find_binary_reader(t.cast("t.IO[t.Any]", input))

        if rv is not None:
            return rv

        raise TypeError("Could not find binary reader for input stream.")

    if input is None:
        input = b""
    elif isinstance(input, str):
        input = input.encode(charset)

    return io.BytesIO(input)

def _echo(self, rv: bytes) -> bytes:
    if not self._paused:
        self._output.write(rv)

    return rv

def __init__(self, copy_to: io.BytesIO) -> None:
    super().__init__()
    self.copy_to = copy_to

def flush(self) -> None:
    super().flush()
    self.copy_to.flush()

def write(self, b: ReadableBuffer) -> int:
    self.copy_to.write(b)
    return super().write(b)

def fileno(self) -> int:
    """Return the file descriptor of the saved original stream when
    ``CliRunner`` runs in ``fd`` mode. Otherwise delegate to
    :class:`~io.TextIOWrapper`, which raises
    :exc:`io.UnsupportedOperation` for a ``BytesIO``-backed buffer.
    """
    if self._original_fd >= 0:
        return self._original_fd
    return super().fileno()

def output(self) -> str:
    """The terminal output as unicode string, as the user would see it.

    .. versionchanged:: 8.2
        No longer a proxy for ``self.stdout``. Now has its own independent stream
        that is mixing `<stdout>` and `<stderr>`, in the order they were written.
    """
    return self.output_bytes.decode(self.runner.charset, "replace").replace(
        "\r\n", "\n"
    )

def stdout(self) -> str:
    """The standard output as unicode string."""
    return self.stdout_bytes.decode(self.runner.charset, "replace").replace(
        "\r\n", "\n"
    )

def stderr(self) -> str:
    """The standard error as unicode string.

    .. versionchanged:: 8.2
        No longer raise an exception, always returns the `<stderr>` string.
    """
    return self.stderr_bytes.decode(self.runner.charset, "replace").replace(
        "\r\n", "\n"
    )

def __repr__(self) -> str:
    exc_str = repr(self.exception) if self.exception else "okay"
    return f"<{type(self).__name__} {exc_str}>"

def __init__(
    self,
    charset: str = "utf-8",
    env: cabc.Mapping[str, str | None] | None = None,
    echo_stdin: bool = False,
    catch_exceptions: bool = True,
    capture: CaptureMode = "sys",
) -> None:
    if capture not in {"sys", "fd"}:
        raise ValueError(
            f"capture={capture!r} is not valid. Choose from 'sys' or 'fd'."
        )
    if capture == "fd" and sys.platform == "win32":
        raise ValueError(
            f"capture={capture!r} is not supported on Windows. Use 'sys'."
        )
    self.charset = charset
    self.env = env or {}
    self.echo_stdin = echo_stdin
    self.catch_exceptions = catch_exceptions
    self.capture = capture

def make_env(
    self, overrides: cabc.Mapping[str, str | None] | None = None
) -> cabc.Mapping[str, str | None]:
    """Returns the environment overrides for invoking a script."""
    rv = dict(self.env)
    if overrides:
        rv.update(overrides)
    return rv

def visible_input(prompt: str | None = None) -> str:
    sys.stdout.write(prompt or "")
    try:
        val = next(text_input).rstrip("\r\n")
    except StopIteration as e:
        raise EOFError() from e
    sys.stdout.write(f"{val}\n")
    sys.stdout.flush()
    return val

def hidden_input(prompt: str | None = None) -> str:
    sys.stdout.write(f"{prompt or ''}\n")
    sys.stdout.flush()
    try:
        return next(text_input).rstrip("\r\n")
    except StopIteration as e:
        raise EOFError() from e

def _getchar(echo: bool) -> str:
    char = sys.stdin.read(1)

    if echo:
        sys.stdout.write(char)

    sys.stdout.flush()
    return char

def should_strip_ansi(
    stream: t.IO[t.Any] | None = None, color: bool | None = None
) -> bool:
    if color is None:
        return not default_color
    return not color

def _guess_type(
    ty: type[t.Any] | ParamType[t.Any] | None,
    default: t.Any | None,
) -> type[t.Any] | tuple[type[t.Any], ...] | ParamType[t.Any] | None:
    """Infer a type from *ty* or *default*.

    Returns *ty* unchanged when it is not ``None``.  Otherwise inspects
    *default* to produce a ``type``, a ``tuple`` of types (for tuple
    defaults), or ``None``.
    """
    if ty is not None:
        return ty

    if default is None:
        return None

    if not isinstance(default, (tuple, list)):
        return type(default)

    # If the default is empty, return None so convert_type falls
    # through to STRING.
    if not default:
        return None

    item = default[0]

    # A sequence of iterables needs to detect the inner types.
    # Can't call convert_type recursively because that would
    # incorrectly unwind the tuple to a single type.
    if isinstance(item, (tuple, list)):
        return tuple(map(type, item))

    return type(item)

def convert_type(
    ty: type | ParamType[t.Any], default: t.Any | None = None
) -> ParamType[t.Any]: ...

def convert_type(
    ty: t.Any | None, default: t.Any | None = None
) -> ParamType[t.Any]: ...

def convert_type(
    ty: t.Any | None = None, default: t.Any | None = None
) -> ParamType[t.Any]:
    """Find the most appropriate :class:`ParamType` for the given Python
    type. If the type isn't provided, it can be inferred from a default
    value.
    """
    guessed = _guess_type(ty, default)
    is_guessed = guessed is not ty

    if isinstance(guessed, tuple):
        return Tuple(guessed)

    if isinstance(guessed, ParamType):
        return guessed

    if guessed is str or guessed is None:
        return STRING

    if guessed is int:
        return INT

    if guessed is float:
        return FLOAT

    if guessed is bool:
        return BOOL

    if is_guessed:
        return STRING

    if __debug__:
        try:
            if issubclass(guessed, ParamType):
                raise AssertionError(
                    f"Attempted to use an uninstantiated parameter type ({guessed})."
                )
        except TypeError:
            # guessed is an instance (correct), so issubclass fails.
            pass

    return FuncParamType(guessed)

def __call__(
    self,
    value: t.Any,
    param: Parameter | None = None,
    ctx: Context | None = None,
) -> _ValueT_co | None:
    if value is not None:
        return self.convert(value, param, ctx)
    return None

def __init__(self, func: t.Callable[[_ValueT_contra], _ValueT_co]) -> None:
    self.name = func.__name__
    self.func = func

def convert(
    self, value: _ValueT_contra, param: Parameter | None, ctx: Context | None
) -> _ValueT_co:
    try:
        return self.func(value)
    except ValueError as exc:
        message = str(exc)

        if not message:
            try:
                message = str(value)
            except UnicodeError:
                message = t.cast("bytes", value).decode("utf-8", "replace")

        self.fail(message, param, ctx)

def convert(
    self, value: _ValueT, param: Parameter | None, ctx: Context | None
) -> _ValueT:
    return value

def convert(
    self, value: t.Any, param: Parameter | None, ctx: Context | None
) -> str:
    if isinstance(value, bytes):
        enc = _get_argv_encoding()
        try:
            return value.decode(enc)
        except UnicodeError:
            fs_enc = sys.getfilesystemencoding()
            if fs_enc != enc:
                try:
                    return value.decode(fs_enc)
                except UnicodeError:
                    return value.decode("utf-8", "replace")
            else:
                return value.decode("utf-8", "replace")
    return str(value)

def __init__(
    self, choices: cabc.Iterable[_ValueT_co], case_sensitive: bool = True
) -> None:
    self.choices = tuple(choices)
    self.case_sensitive = case_sensitive

def to_info_dict(self) -> ChoiceInfoDict[_ValueT_co]:
    return {
        "choices": self.choices,
        "case_sensitive": self.case_sensitive,
        **super().to_info_dict(),
    }

def _normalized_mapping(
    self, ctx: Context | None = None
) -> cabc.Mapping[_ValueT_co, str]:
    """
    Returns mapping where keys are the original choices and the values are
    the normalized values that are accepted via the command line.

    This is a simple wrapper around :meth:`normalize_choice`, use that
    instead which is supported.
    """
    return {
        choice: self.normalize_choice(
            choice=choice,
            ctx=ctx,
        )
        for choice in self.choices
    }

def get_metavar(self, param: Parameter, ctx: Context) -> str | None:
    if param.param_type_name == "option" and not param.show_choices:  # type: ignore[attr-defined]
        choice_metavars = [
            convert_type(type(choice)).name.upper() for choice in self.choices
        ]
        choices_str = "|".join([*dict.fromkeys(choice_metavars)])
    else:
        choices_str = "|".join(
            [str(i) for i in self._normalized_mapping(ctx=ctx).values()]
        )

    # Use curly braces to indicate a required argument.
    if param.required and param.param_type_name == "argument":
        return f"{{{choices_str}}}"

    # Use square braces to indicate an option or optional argument.
    return f"[{choices_str}]"

def get_missing_message(self, param: Parameter, ctx: Context | None) -> str:
    """
    Message shown when no choice is passed.

    .. versionchanged:: 8.2.0 Added ``ctx`` argument.
    """
    return _("Choose from:\n\t{choices}").format(
        choices=",\n\t".join(self._normalized_mapping(ctx=ctx).values())
    )

def convert(
    self, value: t.Any, param: Parameter | None, ctx: Context | None
) -> _ValueT_co:
    """
    For a given value from the parser, normalize it and find its
    matching normalized value in the list of choices. Then return the
    matched "original" choice.
    """
    normed_value = self.normalize_choice(choice=value, ctx=ctx)
    normalized_mapping = self._normalized_mapping(ctx=ctx)

    try:
        return next(
            original
            for original, normalized in normalized_mapping.items()
            if normalized == normed_value
        )
    except StopIteration:
        self.fail(
            self.get_invalid_choice_message(value=value, ctx=ctx),
            param=param,
            ctx=ctx,
        )

def __init__(self, formats: cabc.Sequence[str] | None = None):
    self.formats = formats or [
        "%Y-%m-%d",
        "%Y-%m-%dT%H:%M:%S",
        "%Y-%m-%d %H:%M:%S",
    ]

def _try_to_convert_date(self, value: t.Any, format: str) -> datetime | None:
    try:
        return datetime.strptime(value, format)
    except ValueError:
        return None

def convert(
    self, value: t.Any, param: Parameter | None, ctx: Context | None
) -> datetime:
    if isinstance(value, datetime):
        return value

    for format in self.formats:
        converted = self._try_to_convert_date(value, format)

        if converted is not None:
            return converted

    formats_str = ", ".join(map(repr, self.formats))
    self.fail(
        ngettext(
            "{value!r} does not match the format {format}.",
            "{value!r} does not match the formats {formats}.",
            len(self.formats),
        ).format(value=value, format=formats_str, formats=formats_str),
        param,
        ctx,
    )

def convert(
    self, value: _ValueT_contra, param: Parameter | None, ctx: Context | None
) -> _ValueT_co:
    try:
        return self._number_class(value)
    except ValueError:
        self.fail(
            _("{value!r} is not a valid {number_type}.").format(
                value=value, number_type=self.name
            ),
            param,
            ctx,
        )

def to_info_dict(self) -> NumberRangeInfoDict[_FloatValueT_co]:
    return {
        "min": self.min,
        "max": self.max,
        "min_open": self.min_open,
        "max_open": self.max_open,
        "clamp": self.clamp,
        **super().to_info_dict(),
    }

def convert(
    self, value: _ValueT_contra, param: Parameter | None, ctx: Context | None
) -> _FloatValueT_co:
    import operator

    rv = super().convert(value, param, ctx)
    min = self.min
    max = self.max
    lt_min: bool = min is not None and (
        operator.le if self.min_open else operator.lt
    )(rv, min)
    gt_max: bool = max is not None and (
        operator.ge if self.max_open else operator.gt
    )(rv, max)

    if self.clamp:
        if min is not None and lt_min:
            return self._clamp(min, 1, self.min_open)

        if max is not None and gt_max:
            return self._clamp(max, -1, self.max_open)

    if lt_min or gt_max:
        self.fail(
            _("{value} is not in the range {range}.").format(
                value=rv, range=self._describe_range()
            ),
            param,
            ctx,
        )

    return rv

def __repr__(self) -> str:
    clamp = " clamped" if self.clamp else ""
    return f"<{type(self).__name__} {self._describe_range()}{clamp}>"

def _clamp(self, bound: int, dir: t.Literal[1, -1], open: bool) -> int:
    if not open:
        return bound

    return bound + dir

def __init__(
    self,
    min: float | None = None,
    max: float | None = None,
    min_open: bool = False,
    max_open: bool = False,
    clamp: bool = False,
) -> None:
    super().__init__(
        min=min, max=max, min_open=min_open, max_open=max_open, clamp=clamp
    )

    if (min_open or max_open) and clamp:
        raise TypeError("Clamping is not supported for open bounds.")

def convert(
    self, value: t.Any, param: Parameter | None, ctx: Context | None
) -> bool:
    normalized = self.str_to_bool(value)
    if normalized is None:
        self.fail(
            _(
                "{value!r} is not a valid boolean. Recognized values: {states}"
            ).format(value=value, states=", ".join(sorted(self.bool_states))),
            param,
            ctx,
        )
    return normalized

def convert(
    self, value: uuid.UUID | str, param: Parameter | None, ctx: Context | None
) -> uuid.UUID:
    if isinstance(value, uuid.UUID):
        return value

    value = value.strip()

    try:
        return uuid.UUID(value)
    except ValueError:
        self.fail(
            _("{value!r} is not a valid UUID.").format(value=value), param, ctx
        )

def to_info_dict(self) -> FileInfoDict:
    return {
        "mode": self.mode,
        "encoding": self.encoding,
        **super().to_info_dict(),
    }

def resolve_lazy_flag(self, value: str | os.PathLike[str]) -> bool:
    if self.lazy is not None:
        return self.lazy
    if os.fspath(value) == "-":
        return False
    elif "w" in self.mode:
        return True
    return False

def convert(
    self,
    value: str | os.PathLike[str] | t.IO[t.Any],
    param: Parameter | None,
    ctx: Context | None,
) -> t.IO[t.Any]:
    if _is_file_like(value):
        return value

    try:
        lazy = self.resolve_lazy_flag(value)

        if lazy:
            lf = LazyFile(
                value, self.mode, self.encoding, self.errors, atomic=self.atomic
            )

            if ctx is not None:
                ctx.call_on_close(lf.close_intelligently)

            return t.cast("t.IO[t.Any]", lf)

        f, should_close = open_stream(
            value, self.mode, self.encoding, self.errors, atomic=self.atomic
        )

        # If a context is provided, we automatically close the file
        # at the end of the context execution (or flush out).  If a
        # context does not exist, it's the caller's responsibility to
        # properly close the file.  This for instance happens when the
        # type is used with prompts.
        if ctx is not None:
            if should_close:
                ctx.call_on_close(safecall(f.close))
            else:
                ctx.call_on_close(safecall(f.flush))

        return f
    except OSError as e:
        self.fail(
            f"'{format_filename(value)}': {e.strerror}",
            param,
            ctx,
        )

def to_info_dict(self) -> PathInfoDict:
    return {
        "exists": self.exists,
        "file_okay": self.file_okay,
        "dir_okay": self.dir_okay,
        "writable": self.writable,
        "readable": self.readable,
        "allow_dash": self.allow_dash,
        **super().to_info_dict(),
    }

def coerce_path_result(
    self, value: str | os.PathLike[str]
) -> str | bytes | os.PathLike[str]:
    if self.type is not None and not isinstance(value, self.type):
        if self.type is str:
            return os.fsdecode(value)
        elif self.type is bytes:
            return os.fsencode(value)
        else:
            return t.cast("os.PathLike[str]", self.type(value))

    return value

def convert(
    self,
    value: str | os.PathLike[str],
    param: Parameter | None,
    ctx: Context | None,
) -> str | bytes | os.PathLike[str]:
    rv = value

    dash = b"-" if isinstance(rv, bytes) else "-"
    is_dash = self.file_okay and self.allow_dash and rv == dash

    if not is_dash:
        if self.resolve_path:
            rv = os.path.realpath(rv)

        try:
            st = os.stat(rv)
        except OSError:
            if not self.exists:
                return self.coerce_path_result(rv)
            self.fail(
                _("{name} {filename!r} does not exist.").format(
                    name=self.name.title(), filename=format_filename(value)
                ),
                param,
                ctx,
            )

        if not self.file_okay and stat.S_ISREG(st.st_mode):
            self.fail(
                _("{name} {filename!r} is a file.").format(
                    name=self.name.title(), filename=format_filename(value)
                ),
                param,
                ctx,
            )
        if not self.dir_okay and stat.S_ISDIR(st.st_mode):
            self.fail(
                _("{name} {filename!r} is a directory.").format(
                    name=self.name.title(), filename=format_filename(value)
                ),
                param,
                ctx,
            )

        if self.readable and not os.access(rv, os.R_OK):
            self.fail(
                _("{name} {filename!r} is not readable.").format(
                    name=self.name.title(), filename=format_filename(value)
                ),
                param,
                ctx,
            )

        if self.writable and not os.access(rv, os.W_OK):
            self.fail(
                _("{name} {filename!r} is not writable.").format(
                    name=self.name.title(), filename=format_filename(value)
                ),
                param,
                ctx,
            )

        if self.executable and not os.access(value, os.X_OK):
            self.fail(
                _("{name} {filename!r} is not executable.").format(
                    name=self.name.title(), filename=format_filename(value)
                ),
                param,
                ctx,
            )

    return self.coerce_path_result(rv)

def to_info_dict(self) -> TupleInfoDict:
    return {
        "types": [ty.to_info_dict() for ty in self.types],
        **super().to_info_dict(),
    }

def convert(
    self, value: t.Any, param: Parameter | None, ctx: Context | None
) -> tuple[t.Any, ...]:
    len_type = len(self.types)
    len_value = len(value)

    if len_value != len_type:
        self.fail(
            ngettext(
                "{len_type} values are required, but {len_value} was given.",
                "{len_type} values are required, but {len_value} were given.",
                len_value,
            ).format(len_type=len_type, len_value=len_value),
            param=param,
            ctx=ctx,
        )

    return tuple(
        ty(x, param, ctx) for ty, x in zip(self.types, value, strict=False)
    )

def safecall(func: t.Callable[P, R]) -> t.Callable[P, R | None]:
    """Wraps a function so that it swallows exceptions."""

    def wrapper(*args: P.args, **kwargs: P.kwargs) -> R | None:
        try:
            return func(*args, **kwargs)
        except Exception:
            pass
        return None

    return update_wrapper(wrapper, func)

def make_str(value: t.Any) -> str:
    """Converts a value into a valid string."""
    if isinstance(value, bytes):
        try:
            return value.decode(sys.getfilesystemencoding())
        except UnicodeError:
            return value.decode("utf-8", "replace")
    return str(value)

def get_binary_stream(name: t.Literal["stdin", "stdout", "stderr"]) -> t.BinaryIO:
    """Returns a system stream for byte processing.

    :param name: the name of the stream to open.  Valid names are ``'stdin'``,
                 ``'stdout'`` and ``'stderr'``
    """
    opener = binary_streams.get(name)
    if opener is None:
        raise TypeError(_("Unknown standard stream '{name}'").format(name=name))
    return opener()

def wrapper(*args: P.args, **kwargs: P.kwargs) -> R | None:
    try:
        return func(*args, **kwargs)
    except Exception:
        pass
    return None

def __repr__(self) -> str:
    if self._f is not None:
        return repr(self._f)
    return f"<unopened file '{format_filename(self.name)}' {self.mode}>"

def open(self) -> t.IO[t.Any]:
    """Opens the file if it's not yet open.  This call might fail with
    a :exc:`FileError`.  Not handling this error will produce an error
    that Click shows.
    """
    if self._f is not None:
        return self._f
    try:
        rv, self.should_close = open_stream(
            self.name, self.mode, self.encoding, self.errors, atomic=self.atomic
        )
    except OSError as e:
        from .exceptions import FileError

        raise FileError(self.name, hint=e.strerror) from e
    self._f = rv
    return rv

def close(self) -> None:
    """Closes the underlying file, no matter what."""
    if self._f is not None:
        self._f.close()

def close_intelligently(self) -> None:
    """This function only closes the file if it was opened by the lazy
    file wrapper.  For instance this will never close stdin.
    """
    if self.should_close:
        self.close()

def __iter__(self) -> cabc.Iterator[t.AnyStr]:
    self.open()
    return iter(self._f)  # type: ignore

def flush(self) -> None:
    try:
        self.wrapped.flush()
    except OSError as e:
        import errno

        if e.errno != errno.EPIPE:
            raise

def _make_text_stream(
    stream: t.BinaryIO,
    encoding: str | None,
    errors: str | None,
    force_readable: bool = False,
    force_writable: bool = False,
) -> t.TextIO:
    if encoding is None:
        encoding = get_best_encoding(stream)
    if errors is None:
        errors = "replace"
    return _NonClosingTextIOWrapper(
        stream,
        encoding,
        errors,
        line_buffering=True,
        force_readable=force_readable,
        force_writable=force_writable,
    )

def is_ascii_encoding(encoding: str) -> bool:
    """Checks if a given encoding is ascii."""
    try:
        return codecs.lookup(encoding).name == "ascii"
    except LookupError:
        return False

def get_best_encoding(stream: t.IO[t.Any]) -> str:
    """Returns the default stream encoding if not found."""
    rv = getattr(stream, "encoding", None) or sys.getdefaultencoding()
    if is_ascii_encoding(rv):
        return "utf-8"
    return rv

def _is_binary_reader(stream: t.IO[t.Any], default: bool = False) -> bool:
    try:
        return isinstance(stream.read(0), bytes)
    except Exception:
        return default

def _is_binary_writer(stream: t.IO[t.Any], default: bool = False) -> bool:
    try:
        stream.write(b"")
    except Exception:
        try:
            stream.write("")
            return False
        except Exception:
            pass
        return default
    return True

def _find_binary_reader(stream: t.IO[t.Any]) -> t.BinaryIO | None:
    # We need to figure out if the given stream is already binary.
    # This can happen because the official docs recommend detaching
    # the streams to get binary streams.  Some code might do this, so
    # we need to deal with this case explicitly.
    if _is_binary_reader(stream, False):
        return t.cast(t.BinaryIO, stream)

    buf = getattr(stream, "buffer", None)

    # Same situation here; this time we assume that the buffer is
    # actually binary in case it's closed.
    if buf is not None and _is_binary_reader(buf, True):
        return t.cast(t.BinaryIO, buf)

    return None

def _find_binary_writer(stream: t.IO[t.Any]) -> t.BinaryIO | None:
    # We need to figure out if the given stream is already binary.
    # This can happen because the official docs recommend detaching
    # the streams to get binary streams.  Some code might do this, so
    # we need to deal with this case explicitly.
    if _is_binary_writer(stream, False):
        return t.cast(t.BinaryIO, stream)

    buf = getattr(stream, "buffer", None)

    # Same situation here; this time we assume that the buffer is
    # actually binary in case it's closed.
    if buf is not None and _is_binary_writer(buf, True):
        return t.cast(t.BinaryIO, buf)

    return None

def _is_compatible_text_stream(
    stream: t.TextIO, encoding: str | None, errors: str | None
) -> bool:
    """Check if a stream's encoding and errors attributes are
    compatible with the desired values.
    """
    return _is_compat_stream_attr(
        stream, "encoding", encoding
    ) and _is_compat_stream_attr(stream, "errors", errors)

def get_binary_stdin() -> t.BinaryIO:
    reader = _find_binary_reader(sys.stdin)
    if reader is None:
        raise RuntimeError("Was not able to determine binary stream for sys.stdin.")
    return reader

def get_binary_stdout() -> t.BinaryIO:
    writer = _find_binary_writer(sys.stdout)
    if writer is None:
        raise RuntimeError("Was not able to determine binary stream for sys.stdout.")
    return writer

def get_binary_stderr() -> t.BinaryIO:
    writer = _find_binary_writer(sys.stderr)
    if writer is None:
        raise RuntimeError("Was not able to determine binary stream for sys.stderr.")
    return writer

def get_text_stdin(encoding: str | None = None, errors: str | None = None) -> t.TextIO:
    rv = _get_windows_console_stream(sys.stdin, encoding, errors)
    if rv is not None:
        return rv
    return _force_correct_text_reader(sys.stdin, encoding, errors, force_readable=True)

def get_text_stdout(encoding: str | None = None, errors: str | None = None) -> t.TextIO:
    rv = _get_windows_console_stream(sys.stdout, encoding, errors)
    if rv is not None:
        return rv
    return _force_correct_text_writer(sys.stdout, encoding, errors, force_writable=True)

def get_text_stderr(encoding: str | None = None, errors: str | None = None) -> t.TextIO:
    rv = _get_windows_console_stream(sys.stderr, encoding, errors)
    if rv is not None:
        return rv
    return _force_correct_text_writer(sys.stderr, encoding, errors, force_writable=True)

def _wrap_io_open(
    file: str | os.PathLike[str] | int,
    mode: str,
    encoding: str | None,
    errors: str | None,
) -> t.IO[t.Any]:
    """Handles not passing ``encoding`` and ``errors`` in binary mode."""
    if "b" in mode:
        return open(file, mode)

    return open(file, mode, encoding=encoding, errors=errors)

def open_stream(
    filename: str | os.PathLike[str],
    mode: str = "r",
    encoding: str | None = None,
    errors: str | None = "strict",
    atomic: bool = False,
) -> tuple[t.IO[t.Any], bool]:
    binary = "b" in mode
    filename = os.fspath(filename)

    # Standard streams first. These are simple because they ignore the
    # atomic flag. Use fsdecode to handle Path("-").
    if os.fsdecode(filename) == "-":
        if any(m in mode for m in ["w", "a", "x"]):
            if binary:
                return get_binary_stdout(), False
            return get_text_stdout(encoding=encoding, errors=errors), False
        if binary:
            return get_binary_stdin(), False
        return get_text_stdin(encoding=encoding, errors=errors), False

    # Non-atomic writes directly go out through the regular open functions.
    if not atomic:
        return _wrap_io_open(filename, mode, encoding, errors), True

    # Some usability stuff for atomic writes
    if "a" in mode:
        raise ValueError(
            "Appending to an existing file is not supported, because that"
            " would involve an expensive `copy`-operation to a temporary"
            " file. Open the file in normal `w`-mode and copy explicitly"
            " if that's what you're after."
        )
    if "x" in mode:
        raise ValueError("Use the `overwrite`-parameter instead.")
    if "w" not in mode:
        raise ValueError("Atomic writes only make sense with `w`-mode.")

    # Atomic writes are more complicated.  They work by opening a file
    # as a proxy in the same folder and then using the fdopen
    # functionality to wrap it in a Python file.  Then we wrap it in an
    # atomic file that moves the file over on close.
    import errno
    import random

    try:
        perm: int | None = os.stat(filename).st_mode
    except OSError:
        perm = None

    flags = os.O_RDWR | os.O_CREAT | os.O_EXCL

    if binary:
        flags |= getattr(os, "O_BINARY", 0)

    while True:
        tmp_filename = os.path.join(
            os.path.dirname(filename),
            f".__atomic-write{random.randrange(1 << 32):08x}",
        )
        try:
            fd = os.open(tmp_filename, flags, 0o666 if perm is None else perm)
            break
        except OSError as e:
            if e.errno == errno.EEXIST or (
                os.name == "nt"
                and e.errno == errno.EACCES
                and os.path.isdir(e.filename)
                and os.access(e.filename, os.W_OK)
            ):
                continue
            raise

    if perm is not None:
        os.chmod(tmp_filename, perm)  # in case perm includes bits in umask

    f = _wrap_io_open(fd, mode, encoding, errors)
    af = _AtomicFile(f, tmp_filename, os.path.realpath(filename))
    return t.cast(t.IO[t.Any], af), True

def _is_jupyter_kernel_output(stream: t.IO[t.Any]) -> bool:
    while isinstance(stream, (_FixupStream, _NonClosingTextIOWrapper)):
        stream = stream._stream

    return stream.__class__.__module__.startswith("ipykernel.")

def should_strip_ansi(
    stream: t.IO[t.Any] | None = None, color: bool | None = None
) -> bool:
    if color is None:
        if stream is None:
            stream = sys.stdin
        elif hasattr(stream, "color"):
            # ._termui_impl.MaybeStripAnsi handles stripping ansi itself,
            # so we don't need to strip it here
            return False
        return not isatty(stream) and not _is_jupyter_kernel_output(stream)
    return not color

def isatty(stream: t.IO[t.Any]) -> bool:
    try:
        return stream.isatty()
    except Exception:
        return False

def _make_cached_stream_func(
    src_func: t.Callable[[], t.TextIO | None],
    wrapper_func: t.Callable[[], t.TextIO],
) -> t.Callable[[], t.TextIO | None]:
    cache: cabc.MutableMapping[t.TextIO, t.TextIO] = WeakKeyDictionary()

    def func() -> t.TextIO | None:
        stream = src_func()

        if stream is None:
            return None

        try:
            rv = cache.get(stream)
        except Exception:
            rv = None
        if rv is not None:
            return rv
        rv = wrapper_func()
        try:
            cache[stream] = rv
        except Exception:
            pass
        return rv

    return func

def __del__(self) -> None:
    try:
        self.detach()
    except Exception:
        pass

def isatty(self) -> bool:
    # https://bitbucket.org/pypy/pypy/issue/1803
    return self._stream.isatty()

def read1(self, size: int) -> bytes:
    f = getattr(self._stream, "read1", None)

    if f is not None:
        return t.cast(bytes, f(size))

    return self._stream.read(size)

def readable(self) -> bool:
    if self._force_readable:
        return True
    x = getattr(self._stream, "readable", None)
    if x is not None:
        return t.cast(bool, x())
    try:
        self._stream.read(0)
    except Exception:
        return False
    return True

def writable(self) -> bool:
    if self._force_writable:
        return True
    x = getattr(self._stream, "writable", None)
    if x is not None:
        return t.cast(bool, x())
    try:
        self._stream.write(b"")
    except Exception:
        try:
            self._stream.write(b"")
        except Exception:
            return False
    return True

def seekable(self) -> bool:
    x = getattr(self._stream, "seekable", None)
    if x is not None:
        return t.cast(bool, x())
    try:
        self._stream.seek(self._stream.tell())
    except Exception:
        return False
    return True

def close(self, delete: bool = False) -> None:
    if self.closed:
        return
    self._f.close()
    os.replace(self._tmp_filename, self._real_filename)
    self.closed = True

def _get_argv_encoding() -> str:
    import locale

    return locale.getpreferredencoding()

def _get_windows_console_stream(
    f: t.TextIO, encoding: str | None, errors: str | None
) -> t.TextIO | None:
    return None

def func() -> t.TextIO | None:
    stream = src_func()

    if stream is None:
        return None

    try:
        rv = cache.get(stream)
    except Exception:
        rv = None
    if rv is not None:
        return rv
    rv = wrapper_func()
    try:
        cache[stream] = rv
    except Exception:
        pass
    return rv

def _has_binary_buffer(
    stream: t.BinaryIO | t.TextIO,
) -> t.TypeGuard[_BufferedTextPagerStream]:
    # TextIO is wider than TextIOWrapper; text-only streams such as StringIO
    # are valid TextIO values but do not expose a binary buffer to wrap.
    return getattr(stream, "buffer", None) is not None

def _pager_contextmanager(
    color: bool | None = None,
) -> t.ContextManager[tuple[t.BinaryIO | t.TextIO, str, bool]]:
    """Decide what method to use for paging through text."""
    stdout = _default_text_stdout()

    # There are no standard streams attached to write to. For example,
    # pythonw on Windows.
    if stdout is None:
        stdout = StringIO()

    if not isatty(sys.stdin) or not isatty(stdout):
        return _nullpager(stdout, color)

    # Split using POSIX mode (the default) so that quote characters are
    # stripped from tokens and quoted Windows paths are preserved.
    # Non-POSIX mode retains quotes in tokens, and wrapping tokens
    # with shlex.quote re-introduces quoting issues on Windows.
    pager_cmd_parts = shlex.split(os.environ.get("PAGER", ""))
    if pager_cmd_parts:
        if WIN:
            return _tempfilepager(pager_cmd_parts, color)
        return _pipepager(pager_cmd_parts, color)

    if os.environ.get("TERM") in ("dumb", "emacs"):
        return _nullpager(stdout, color)
    if WIN or sys.platform.startswith("os2"):
        return _tempfilepager(["more"], color)
    return _pipepager(["less"], color)

def open_url(url: str, wait: bool = False, locate: bool = False) -> int:
    import subprocess

    def _unquote_file(url: str) -> str:
        from urllib.parse import unquote

        if url.startswith("file://"):
            url = unquote(url[7:])

        return url

    if sys.platform == "darwin":
        args = ["open"]
        if wait:
            args.append("-W")
        if locate:
            args.append("-R")
        args.append(_unquote_file(url))
        null = open("/dev/null", "w")
        try:
            return subprocess.Popen(args, stderr=null).wait()
        finally:
            null.close()
    elif WIN:
        if locate:
            url = _unquote_file(url)
            args = ["explorer", "/select,", url]
            try:
                return subprocess.call(args)
            except OSError:
                return 127
        else:
            try:
                os.startfile(url)  # type: ignore[attr-defined]
            except OSError:
                return 127
            return 0
    elif CYGWIN:
        if locate:
            url = _unquote_file(url)
            args = ["cygstart", os.path.dirname(url)]
        else:
            args = ["cygstart"]
            if wait:
                args.append("-w")
            args.append(url)
        try:
            return subprocess.call(args)
        except OSError:
            # Command not found
            return 127

    try:
        if locate:
            url = os.path.dirname(_unquote_file(url)) or "."
        else:
            url = _unquote_file(url)
        c = subprocess.Popen(["xdg-open", url])
        if wait:
            return c.wait()
        return 0
    except OSError:
        if url.startswith(("http://", "https://")) and not locate and not wait:
            import webbrowser

            webbrowser.open(url)
            return 0
        return 1

def __iter__(self) -> cabc.Iterator[V]:
    if not self.entered:
        raise RuntimeError("You need to use progress bars in a with block.")
    self.render_progress()
    return self.generator()

def render_finish(self) -> None:
    if self.hidden or not self._is_atty:
        return
    self.file.write(AFTER_BAR)
    self.file.flush()

def pct(self) -> float:
    if self.finished:
        return 1.0
    return min(self.pos / (float(self.length or 1) or 1), 1.0)

def time_per_iteration(self) -> float:
    if not self.avg:
        return 0.0
    return sum(self.avg) / float(len(self.avg))

def eta(self) -> float:
    if self.length is not None and not self.finished:
        return self.time_per_iteration * (self.length - self.pos)
    return 0.0

def format_eta(self) -> str:
    if self.eta_known:
        t = int(self.eta)
        seconds = t % 60
        t //= 60
        minutes = t % 60
        t //= 60
        hours = t % 24
        t //= 24
        if t > 0:
            return "{d}{day_label} {h:02}:{m:02}:{s:02}".format(
                d=t,
                day_label=_("d"),
                h=hours,
                m=minutes,
                s=seconds,
            )
        else:
            return f"{hours:02}:{minutes:02}:{seconds:02}"
    return ""

def format_pos(self) -> str:
    pos = str(self.pos)
    if self.length is not None:
        pos += f"/{self.length}"
    return pos

def format_bar(self) -> str:
    if self.length is not None:
        bar_length = int(self.pct * self.width)
        bar = self.fill_char * bar_length
        bar += self.empty_char * (self.width - bar_length)
    elif self.finished:
        bar = self.fill_char * self.width
    else:
        chars = list(self.empty_char * (self.width or 1))
        if self.time_per_iteration != 0:
            chars[
                int(
                    (math.cos(self.pos * self.time_per_iteration) / 2.0 + 0.5)
                    * self.width
                )
            ] = self.fill_char
        bar = "".join(chars)
    return bar

def format_progress_line(self) -> str:
    show_percent = self.show_percent

    info_bits = []
    if self.length is not None and show_percent is None:
        show_percent = not self.show_pos

    if self.show_pos:
        info_bits.append(self.format_pos())
    if show_percent:
        info_bits.append(self.format_pct())
    if self.show_eta and self.eta_known and not self.finished:
        info_bits.append(self.format_eta())
    if self.item_show_func is not None:
        item_info = self.item_show_func(self.current_item)
        if item_info is not None:
            info_bits.append(item_info)

    return (
        self.bar_template
        % {
            "label": self.label,
            "bar": self.format_bar(),
            "info": self.info_sep.join(info_bits),
        }
    ).rstrip()

def make_step(self, n_steps: int) -> None:
    self.pos += n_steps
    if self.length is not None and self.pos >= self.length:
        self.finished = True

    if (time.time() - self.last_eta) < 1.0:
        return

    self.last_eta = time.time()

    # self.avg is a rolling list of length <= 7 of steps where steps are
    # defined as time elapsed divided by the total progress through
    # self.length.
    if self.pos:
        step = (time.time() - self.start) / self.pos
    else:
        step = time.time() - self.start

    self.avg = self.avg[-6:] + [step]

    self.eta_known = self.length is not None

def __init__(self, stream: t.IO[bytes], *, color: bool, **kwargs: t.Any):
    super().__init__(stream, **kwargs)
    self.color = color

def write(self, text: str) -> int:
    if not self.color:
        text = strip_ansi(text)
    return super().write(text)

def get_editor(self) -> str:
    if self.editor is not None:
        return self.editor
    for key in "VISUAL", "EDITOR":
        rv = os.environ.get(key)
        if rv:
            return rv
    if WIN:
        return "notepad"

    from shutil import which

    for editor in "sensible-editor", "vim", "nano":
        if which(editor) is not None:
            return editor
    return "vi"

def edit_files(self, filenames: cabc.Iterable[str]) -> None:
    """Open files in the user's editor."""
    import shlex
    import subprocess

    editor = self.get_editor()
    environ: dict[str, str] | None = None

    if self.env:
        environ = os.environ.copy()
        environ.update(self.env)

    try:
        # Split in POSIX mode (the default) for the same reasons as
        # in pager(): strips quotes from tokens and preserves quoted
        # Windows paths.
        c = subprocess.Popen(
            args=shlex.split(editor) + list(filenames),
            env=environ,
        )
        exit_code = c.wait()
        if exit_code != 0:
            raise ClickException(
                _("{editor}: Editing failed").format(editor=editor)
            )
    except OSError as e:
        raise ClickException(
            _("{editor}: Editing failed: {e}").format(editor=editor, e=e)
        ) from e

def edit(self, text: str | bytes | bytearray | None) -> str | bytes | None:
    import tempfile

    if text is None:
        data: bytes | bytearray = b""
    elif isinstance(text, (bytes, bytearray)):
        data = text
    else:
        if text and not text.endswith("\n"):
            text += "\n"

        if WIN:
            data = text.replace("\n", "\r\n").encode("utf-8-sig")
        else:
            data = text.encode("utf-8")

    fd, name = tempfile.mkstemp(prefix="editor-", suffix=self.extension)
    f: t.BinaryIO

    try:
        with os.fdopen(fd, "wb") as f:
            f.write(data)

        # If the filesystem resolution is 1 second, like Mac OS
        # 10.12 Extended, or 2 seconds, like FAT32, and the editor
        # closes very fast, require_save can fail. Set the modified
        # time to be 2 seconds in the past to work around this.
        os.utime(name, (os.path.getatime(name), os.path.getmtime(name) - 2))
        # Depending on the resolution, the exact value might not be
        # recorded, so get the new recorded value.
        timestamp = os.path.getmtime(name)

        self.edit_files((name,))

        if self.require_save and os.path.getmtime(name) == timestamp:
            return None

        with open(name, "rb") as f:
            rv = f.read()

        if isinstance(text, (bytes, bytearray)):
            return rv

        return rv.decode("utf-8-sig").replace("\r\n", "\n")
    finally:
        os.unlink(name)

def _unquote_file(url: str) -> str:
    from urllib.parse import unquote

    if url.startswith("file://"):
        url = unquote(url[7:])

    return url

def raw_terminal() -> cabc.Iterator[int]:
    f: t.TextIO | None
    fd: int

    if not isatty(sys.stdin):
        f = open("/dev/tty")
        fd = f.fileno()
    else:
        fd = sys.stdin.fileno()
        f = None

    try:
        old_settings = termios.tcgetattr(fd)

        try:
            tty.setraw(fd)
            yield fd
        finally:
            termios.tcsetattr(fd, termios.TCSADRAIN, old_settings)
            sys.stdout.flush()

            if f is not None:
                f.close()
    except termios.error:
        pass

def _wrap_chunks(self, chunks: list[str]) -> list[str]:
    """Wrap chunks counting widths in visible characters.

    Mirrors the algorithm of :meth:`textwrap.TextWrapper._wrap_chunks`
    with every width measurement routed through
    :func:`click._compat.term_len` instead of :func:`len`, so ANSI escape
    bytes in chunks, indents, or the placeholder do not inflate the count.

    .. seealso::
        :class:`textwrap.TextWrapper` in the Python standard library documentation:
        https://docs.python.org/3/library/textwrap.html#textwrap.TextWrapper

        Reference implementation in CPython:
        https://github.com/python/cpython/blob/main/Lib/textwrap.py
    """
    lines: list[str] = []
    if self.width <= 0:
        raise ValueError(f"invalid width {self.width!r} (must be > 0)")
    if self.max_lines is not None:
        if self.max_lines > 1:
            indent = self.subsequent_indent
        else:
            indent = self.initial_indent
        if term_len(indent) + term_len(self.placeholder.lstrip()) > self.width:
            raise ValueError("placeholder too large for max width")

    chunks.reverse()

    while chunks:
        cur_line: list[str] = []
        cur_len = 0

        if lines:
            indent = self.subsequent_indent
        else:
            indent = self.initial_indent

        width = self.width - term_len(indent)

        if self.drop_whitespace and chunks[-1].strip() == "" and lines:
            del chunks[-1]

        while chunks:
            n = term_len(chunks[-1])

            if cur_len + n <= width:
                cur_line.append(chunks.pop())
                cur_len += n

            else:
                break

        if chunks and term_len(chunks[-1]) > width:
            self._handle_long_word(chunks, cur_line, cur_len, width)
            cur_len = sum(map(term_len, cur_line))

        if self.drop_whitespace and cur_line and cur_line[-1].strip() == "":
            cur_len -= term_len(cur_line[-1])
            del cur_line[-1]

        if cur_line:
            if (
                self.max_lines is None
                or len(lines) + 1 < self.max_lines
                or (
                    not chunks
                    or self.drop_whitespace
                    and len(chunks) == 1
                    and not chunks[0].strip()
                )
                and cur_len <= width
            ):
                lines.append(indent + "".join(cur_line))
            else:
                while cur_line:
                    if (
                        cur_line[-1].strip()
                        and cur_len + term_len(self.placeholder) <= width
                    ):
                        cur_line.append(self.placeholder)
                        lines.append(indent + "".join(cur_line))
                        break
                    cur_len -= term_len(cur_line[-1])
                    del cur_line[-1]
                else:
                    if lines:
                        prev_line = lines[-1].rstrip()
                        if (
                            term_len(prev_line) + term_len(self.placeholder)
                            <= self.width
                        ):
                            lines[-1] = prev_line + self.placeholder
                            break
                    lines.append(indent + self.placeholder.lstrip())
                break

    return lines

def indent_only(self, text: str) -> str:
    rv = []

    for idx, line in enumerate(text.splitlines()):
        indent = self.initial_indent

        if idx > 0:
            indent = self.subsequent_indent

        rv.append(f"{indent}{line}")

    return "\n".join(rv)

def _get_text_stdin(buffer_stream: t.BinaryIO) -> t.TextIO:
    text_stream = _NonClosingTextIOWrapper(
        io.BufferedReader(_WindowsConsoleReader(STDIN_HANDLE)),
        "utf-16-le",
        "strict",
        line_buffering=True,
    )
    return t.cast(t.TextIO, ConsoleStream(text_stream, buffer_stream))

def _get_text_stdout(buffer_stream: t.BinaryIO) -> t.TextIO:
    text_stream = _NonClosingTextIOWrapper(
        io.BufferedWriter(_WindowsConsoleWriter(STDOUT_HANDLE)),
        "utf-16-le",
        "strict",
        line_buffering=True,
    )
    return t.cast(t.TextIO, ConsoleStream(text_stream, buffer_stream))

def _get_text_stderr(buffer_stream: t.BinaryIO) -> t.TextIO:
    text_stream = _NonClosingTextIOWrapper(
        io.BufferedWriter(_WindowsConsoleWriter(STDERR_HANDLE)),
        "utf-16-le",
        "strict",
        line_buffering=True,
    )
    return t.cast(t.TextIO, ConsoleStream(text_stream, buffer_stream))

def _is_console(f: t.TextIO) -> bool:
    if not hasattr(f, "fileno"):
        return False

    try:
        fileno = f.fileno()
    except (OSError, io.UnsupportedOperation):
        return False

    handle = msvcrt.get_osfhandle(fileno)
    return bool(GetConsoleMode(handle, byref(DWORD())))

def _get_windows_console_stream(
    f: t.TextIO, encoding: str | None, errors: str | None
) -> t.TextIO | None:
    if (
        get_buffer is None
        or encoding not in {"utf-16-le", None}
        or errors not in {"strict", None}
        or not _is_console(f)
    ):
        return None

    func = _stream_factories.get(f.fileno())
    if func is None:
        return None

    b = getattr(f, "buffer", None)

    if b is None:
        return None

    return func(b)

def isatty(self) -> t.Literal[True]:
    super().isatty()
    return True

def readinto(self, b: Buffer) -> int:
    bytes_to_be_read = len(b)
    if not bytes_to_be_read:
        return 0
    elif bytes_to_be_read % 2:
        raise ValueError(
            "cannot read odd number of bytes from UTF-16-LE encoded console"
        )

    buffer = get_buffer(b, writable=True)
    code_units_to_be_read = bytes_to_be_read // 2
    code_units_read = c_ulong()

    rv = ReadConsoleW(
        HANDLE(self.handle),
        buffer,
        code_units_to_be_read,
        byref(code_units_read),
        None,
    )
    if GetLastError() == ERROR_OPERATION_ABORTED:
        # wait for KeyboardInterrupt
        time.sleep(0.1)
    if not rv:
        raise OSError(_("Windows error: {error}").format(error=GetLastError()))

    if buffer[0] == EOF:
        return 0
    return 2 * code_units_read.value

def _get_error_message(errno: int) -> str:
    if errno == ERROR_SUCCESS:
        return "ERROR_SUCCESS"
    elif errno == ERROR_NOT_ENOUGH_MEMORY:
        return "ERROR_NOT_ENOUGH_MEMORY"
    return _("Windows error: {error}").format(error=errno)

def __init__(self, text_stream: t.TextIO, byte_stream: t.BinaryIO) -> None:
    self._text_stream = text_stream
    self.buffer = byte_stream

def write(self, x: t.AnyStr) -> int:
    if isinstance(x, str):
        return self._text_stream.write(x)
    try:
        self.flush()
    except Exception:
        pass
    return self.buffer.write(x)

def writelines(self, lines: cabc.Iterable[t.AnyStr]) -> None:
    for line in lines:
        self.write(line)

